import{r,o as a,a as i,b as e,d as o,F as l,c as t,e as s}from"./app.d8523fce.js";import{_ as c}from"./plugin-vue_export-helper.21dcd24c.js";const d={},h=t('<h1 id="_2-3-csrf-defense-best-practices" tabindex="-1"><a class="header-anchor" href="#_2-3-csrf-defense-best-practices" aria-hidden="true">#</a> 2.3 CSRF Defense Best Practices</h1><h2 id="what-are-the-primary-defense-mechanisms-against-csrf" tabindex="-1"><a class="header-anchor" href="#what-are-the-primary-defense-mechanisms-against-csrf" aria-hidden="true">#</a> What are the primary defense mechanisms against CSRF ?</h2><h3 id="synchronizer-tokens" tabindex="-1"><a class="header-anchor" href="#synchronizer-tokens" aria-hidden="true">#</a> Synchronizer Tokens</h3><ul><li><strong>Description</strong>: The server adds a request parameter to each form, assigning the field a different random value for each session (or for each request.) The server confirms that each subsequent request has this field and that its value matches the one assigned for the session.</li><li><strong>Token type</strong>: Random</li><li><strong>Strategy</strong>: Stored in HTTP session and sent as request parameter.</li><li><strong>Server-side validation</strong>: Session token against request parameter.</li></ul><h3 id="double-submitted-cookie" tabindex="-1"><a class="header-anchor" href="#double-submitted-cookie" aria-hidden="true">#</a> Double-Submitted Cookie</h3><ul><li><strong>Description</strong>: The random token value is saved in a cookie on the client. Every subsequent request must include the same value in a request parameter. On each request the server confirms that the request parameter is present and that its value matches that in the cookie.</li><li><strong>Token type</strong>: Random</li><li><strong>Strategy</strong>: Sent as a cookie and request parameter.</li><li><strong>Server-side validation</strong>: Cookie token against request parameter.</li></ul><h3 id="custom-request-header" tabindex="-1"><a class="header-anchor" href="#custom-request-header" aria-hidden="true">#</a> Custom Request Header</h3><ul><li><strong>Description</strong>: Using a custom header works as a defense because only JavaScript can create custom headers, and the browser\u2019s single-origin policy (SOP) blocks cross-site JavaScript calls.</li><li><strong>Token type</strong>: No matter.</li><li><strong>Strategy</strong>: Sent as Request header.</li><li><strong>Server-side validation</strong>: Check request header exists.</li></ul><h3 id="encrypted-token" tabindex="-1"><a class="header-anchor" href="#encrypted-token" aria-hidden="true">#</a> Encrypted Token</h3><ul><li><strong>Description</strong>: Encrypting the token value using a private key known only on the server. The encrypted value should be a time stamp. Validate subsequent requests by confirming that each contains the request parameter, that you can decrypt the field value, that the decrypted value is a timestamp, and that the timestamp has not expired.</li><li><strong>Token type</strong>: Signed/ Encrypted</li><li><strong>Strategy</strong>: Sent as Request header.</li><li><strong>Server-side validation</strong>: Check request header exists.</li></ul><div class="custom-container warning"><p class="custom-container-title">WARNING</p><p>XSS Attacks can defeat any CSRF protection even if it perfectly implemented !</p><p>XSS attackers can retrieve your tokens from the user&#39;s browser if your application is not protected.</p><p><strong>Solid XSS prevention is a mandatory prerequisite for CSRF defenses.</strong></p></div><h2 id="what-are-the-bad-misconceptions-about-csrf-defenses" tabindex="-1"><a class="header-anchor" href="#what-are-the-bad-misconceptions-about-csrf-defenses" aria-hidden="true">#</a> What are the bad misconceptions about CSRF defenses ?</h2><p>Here are some myths which unfortunately will not save your application from CSRF attacks:</p><ul><li><strong>Using a secret cookie:</strong> even secret cookies are submitted with every request The authentication tokens will be submitted in any case !</li><li><strong>Only accepting POST requests:</strong> Attackers have numerous methods to trick a victim into submitting a forged POST request.</li><li><strong>Multi-Step transactions:</strong> Attackers can always predict and deduce transaction steps.</li><li><strong>URL rewriting:</strong> The session cookie is exposed in the url which introduces another security flaw.</li><li><strong>HTTPS alone</strong> does nothing to defend against CSRF by itself.</li><li><strong>http_only</strong> session cookie will not protect you from CSRF.</li><li><strong>JSON APIs</strong> are also vulnerable to CSRF attacks.</li><li><strong>Same-site Cookie Attribute</strong> can be useful against CSRF but not sufficient by itself because it is not support by all browsers and can be bypassed by attackers.</li></ul><h2 id="what-can-i-do-to-continuously-prevent-csrf-attacks" tabindex="-1"><a class="header-anchor" href="#what-can-i-do-to-continuously-prevent-csrf-attacks" aria-hidden="true">#</a> What can I do to continuously prevent CSRF attacks ?</h2>',15),u=t("<li><p>Use built-in CSRF protection in your Framework. Check the Security Hardening by Framework section bellow.</p></li><li><p>CSRF prevention needs to be done on both client (front-end) and server (back-end) side:</p><ul><li><p>Server side prevention measures:</p><ul><li>Reject requests that have mismatched CSRF cookie/header.</li><li>Send a randomly generated CSRF cookie to the client (cannot be http_only).</li><li>Use CORS to prevent cross-origin AJAX from untrusted pages.</li></ul></li><li><p>Client side prevention measures:</p><ul><li>Send the CSRF value for each request.</li><li>Send a matching header with each request.</li></ul></li></ul></li>",2),p=s("Apply "),g={href:"https://cheatsheetseries.owasp.org/cheatsheets/Cross-Site_Request_Forgery_Prevention_Cheat_Sheet.html",target:"_blank",rel:"noopener noreferrer"},m=s("OWASP CSRF prevention cheat sheet"),f=e("li",null,[e("p",null,"Use sonarLint in your IDE in order to alert on vulnerable code while you are developing.")],-1),y=e("li",null,[e("p",null,"Request code reviews from acknowledged Security Reviewers in your team.")],-1),S=e("li",null,[e("p",null,"Scan your code with automated code analysis tools in your merge requests and prevent pushing any vulnerable code in your application.")],-1),b=e("li",null,[e("p",null,"Perform regular SAST scans of your code and fix the vulnerabilities raised.")],-1),v=e("li",null,[e("p",null,"Perform regular penetration testing with DAST tools like OWASP ZAP and fix the findings.")],-1);function k(_,q){const n=r("ExternalLinkIcon");return a(),i(l,null,[h,e("ul",null,[u,e("li",null,[e("p",null,[p,e("a",g,[m,o(n)])])]),f,y,S,b,v])],64)}var R=c(d,[["render",k]]);export{R as default};
